SELECT ci.item_name, ci.price
FROM clothing_items ci
WHERE ci.price = (SELECT MAX(price) FROM clothing_items);

SELECT COUNT(DISTINCT customer_id) AS number_of_customers
FROM customers
WHERE region = 'United States';

SELECT AVG(fit_accuracy) AS average_fit_accuracy
FROM feedback
WHERE sizing_feedback LIKE '%slightly tight in the shoulders%';

SELECT email
FROM customers
WHERE customer_id IN (0, 1);
